<template>
    <section>
        <loader :is-visible="isLoading"></loader>
        <tg-list ref="tgList" :listType="listType" :IsShowAction="false" :showCheckBox="true"
            ModuleName="Phase" SubModuleCode="Phase" IdentityColumn="PHASE_ID"
            :HeaderText="$t('Phase')" :ListData="PhaseData" :HeaderData="Headers" :widgets="widgets"
            :HeaderButtons="listheaderbuttons" :TotalRecords="TotalRecords" :SearchFields="leftSearchFields" IsSearchFieldsOnTop="false" SearchPosition="top"
            :RenderRowActionMethod="renderActions" :ListDataCallBackFunction="FetchData" :SortExp="SortExp"
            :SortBy="SortBy" :LegendArray="LegendArray"
            :NorecordfoundText="$t('NoRecordfound')" v-on:LeftsearchButtonClick="leftCommonSearch" :isNewDesign="isNewDesign"
            v-on:PagerButtonClick="pagerMethod" v-on:HeaderButtonClick="commonHeaderButtonClick"
            v-on:ActionButtonClick="actionButtonClick" v-on:SortdataButtonClick="sortdata" :Key="Key" :routeInfo="$router">    
            <template v-slot:slotdata="{ data }">
                <template v-if="data.column.COLUMN_NAME == 'STATUS_ID'">                  
                    <select @change="Updatestatus(data.row.PHASE_ID,data.row.STATUS_ID)" class="w-100 text-center text-white" :style="BIconBorderStyle(data.row.STATUS_ID)"  v-model="data.row.STATUS_ID">
                        <option value="1001"> Active </option>
                        <option value="1002" > Inactive </option>
                    </select>
                </template>
                <template v-if="data.column.COLUMN_NAME == 'PHASE_NAME'">
                          <a class="text-primary" @click="OpenEditModel(data.row)">{{data.row.PHASE_NAME  }}</a>        
                </template>
            </template>           
        </tg-list>
        <transition name="modal">
            <div class="my-popups">
                <loader :is-visible="isLoading"></loader>
                <div class="modal d-block dialog" v-if="isShowPhaseModel">
                    <div class="modal-dialog modal-lg">
                        <div class="modal-content">
                            <div class="modal-header">
                                <h4 class="modal-title">{{PHASE_ID ==0 ? $t('AddPhase') :  $t('EditPhase')}}</h4>

                                <button type="button" class="close" v-on:click="ClosePhaseModel">
                                    <em class="fa fa-times" aria-hidden="true"></em>
                                </button>

                            </div>

                            <div class="modal-body">
                                <div class="col-md-12">
                                    <div class="listing">
                                        <dynamic-form lang="en" :buttons="buttons" :schema="FormSchema" ref="AddPhaseRecord" :mandatorytext='MandatoryString'
                                        v-on:OnSubmit="OnSubmit"></dynamic-form>
                                    </div>
                                </div>
                            </div>
                        </div>
                    </div>
                </div>
            </div>
        </transition>
    </section>
</template>
<script>
import DataService from '../../../services/DataService';
import PhaseListSchema from './PhaseListSchema.js';
export default {
    data() {
        return{
            Key:0,
            isShowPhaseModel:false,
            isLoading:false,
            TotalRecords:0,
            listType:['List'],
            widgets:[],
            Headers:[
                 {
                    "COLUMN_NAME": "PHASE_NAME",
                    "DATA_TYPE": "string",
                    "SORTABLE": true,
                    "VISIBLE": true,
                    "DISPLAY_NAME": this.$t('PHASE_NAME'),
                    "DISPLAY_ORDER": 1,
                    settings: {
                        isInSlot: true
                    }
                },
                {
                    "COLUMN_NAME": "PHASE_DESC",
                    "DATA_TYPE": "string",
                    "SORTABLE": true,
                    "VISIBLE": true,
                    "DISPLAY_NAME": this.$t('PHASE_DESC'),
                    "DISPLAY_ORDER": 2
                },
                {
                    "COLUMN_NAME": "STATUS_ID",
                    "DATA_TYPE": "string",
                    "SORTABLE": true,
                    "VISIBLE": true,
                    "DISPLAY_NAME": this.$t('STATUS_ID'),
                    "DISPLAY_ORDER": 3,
                    settings: {
                        isInSlot: true
                    }
                }
            ],
            listheaderbuttons:PhaseListSchema.buttons,
            leftSearchFields:[  {
                fieldName: this.$t('Phase Name'),
                fieldType: "text",
                fieldSearchConditionName: [''],
                paramName: "phase_name",
                isSearch: true,
                value: "",
                listOptions: []
            }],
            FormSchema: [
                {
                    layoutType: "double",
                    Data: [
                    {
                            astype: "TextField",                                                
                            label: this.$t('PhaseName'),
                            name: "PhaseName",
                            value: "",                            
                            placeholder: this.$t('Enter Phase Name'),
                            validationRules: { "required": true, max: 100 },
                        },
                        {
                            astype: "SelectField",                                                
                            label: this.$t('Status'),
                            name: "Status",
                            value: "", 
                            config: {
                                options: [{name:'Active',value:1001},{name:'InActive',value:1002}]
                            },                           
                            placeholder: this.$t('Select Status'),
                            validationRules: { "required": true, max: 100 },
                        },


                    ],
                },
                {
                    layoutType: "single",
                    Data: [
                        {
                            astype: "TextAreaField",                 
                            label: this.$t('Description'),
                            name: "Description",
                            value: "",  
                            validationRules: { "required": false, max: 4000 },
                            config: {
                                rows:5
                            }
                        }
                    ]
                }

            ],
            buttons: [
                {
                    type: "submit",
                    class: "btn btn-success",
                    text: "<i class='fa fa-save pr-2'></i>Save",
                    isVisible:true
                },            
                {
                    type: "button",
                    class: "btn btn-danger",
                    text: "<i class='fa fa-close pr-2'></i>Cancel",
                    onClick: this.ClosePhaseModel,
                },
            ],
            isNewDesign:false,
            PageNumber: 1,
            PageSize: 10,
            statusId:0,
            SortExp:'',
            SortBy:'',
            LegendArray:[],
            PhaseData:[],
            searchCondition:'',
            StatusListForListing:[{STATUS:'Active',STATUS_ID:1001,STATUS_COLOR: "#ffffff", STATUS_BG_COLOR: "#28a745" },{STATUS:'Inactive',STATUS_ID:1002,STATUS_COLOR: "#ffffff", STATUS_BG_COLOR: "#d72435"}]
            ,PHASE_ID:0,
        }
    },  
    created:function(){
        debugger
        var ths=this;
         ths.FetchData();
    },
    methods:{
        BIconBorderStyle(id){
            if(id==1001){
                return {
                    'background-color' : 'rgb(40, 167, 69)',
                    'color' : 'rgb(255, 255, 255)'
                }
            }
            else{
                return {
                    'background-color' : 'rgb(215, 36, 53)',
                    'color' : 'rgb(255, 255, 255)'
                }
            }
        },
       async OpenEditModel(data)
        {
           var vm=this;
           var url = 'controller=Project&action=AddUpdatePhase'
            await DataService.CheckPrivilege(url).then(async function (response) {
                if (response.data) {
                vm.isShowPhaseModel=true;
                 vm.PHASE_ID=data.PHASE_ID;
                 vm.FormSchema[0].Data[0].value=data.PHASE_NAME;
                 vm.FormSchema[0].Data[1].value=data.STATUS_ID;
                 vm.FormSchema[1].Data[0].value=data.PHASE_DESC;
                } else {
                    vm.ShowAlert(vm.$t('NotAuthorizedSection'), "failure", true, "Alert");
                }
            });


        },
        commonHeaderButtonClick: function (event) {
            switch (event.callbackfunction) {
                case "AddPhase":
                    this.AddPhase();
                    break;
                case "ActivePhase":
                    this.ActiveInActivePhase(0,'Active');
                    break;
                case "InctivePhase":
                    this.ActiveInActivePhase(0,'InActive');
                    break;
                case "DeletePhase":
                    this.ActiveInActivePhase(0,'Delete');
                    break;
            }
        },
        pagerMethod(value) {
            this.PageSize = value.PageSize;
            this.PageNumber = value.PageNumber;
            this.FetchData();
        },
        actionButtonClick(){},
        FetchData:function(){                        
            var ths=this;
            ths.isLoading=true;
            var url=`search=${ths.searchCondition}&pageSize=${ths.PageSize}&pageNum=${ths.PageNumber}&sortBy=${ths.SortBy}&sortExp=${ths.SortExp}`;            
            DataService.GetPhaseData(url).then(response =>{                
                ths.isLoading=false;              
                if(response.data.result.Data.length>0){                    
                    ths.PhaseData=response.data.result.Data;
                    ths.PhaseData.forEach(function(item){
                        item.isCheckBoxDisabled = false;
                        if (item.IsDisable == 1) {
                            item.isCheckBoxDisabled = true;
                        }
                        if (item.CREATED_AT != '') {
                            item.CREATED_AT = new Date(item.CREATED_AT);
                        }
                    })
                    ths.TotalRecords=response.data.result.Data[0].TOTAL;            
                    ths.TotalPages = Math.ceil(ths.TotalRecords / ths.PageSize);
                    ths.CurrentPage = ths.PageNumber;
                    ths.listheaderbuttons[1].isdisabled = true;
                    ths.listheaderbuttons[2].isdisabled = true;
                    ths.listheaderbuttons[3].isdisabled = true;
                }
                else{
                    ths.PhaseData=[];
                    ths.TotalRecords=0;
                }
            });
        },
        renderActions:function(){},
        leftCommonSearch: function (value) {
            this.PageNumber = value.PageNumber;
            this.isPaged = 1;
            if (typeof value.searchCondition != 'undefined') {
                if (value.searchConditionJson != '') {
                    this.searchCondition = value.searchConditionJson.split('=')[1];
                } else {
                    this.searchCondition = value.searchCondition;
                }
            }
            else {
                this.searchCondition = "";
            }
            this.FetchData();
        },
        sortdata: function (s) {
            var SortDir = "sort tb_headerSortDown";
            this.SortBy = s;
            if (s === this.SortBy) {
                if (this.SortExp == "") {
                    this.SortExp = "ASC";
                    SortDir = "sort tb_headerSortDown";
                }
                else if (this.SortExp == "ASC") {
                    this.SortExp = "DESC";
                    SortDir = "sort tb_headerSortUp";
                }
                else {
                    this.SortExp = "ASC";
                    SortDir = "sort tb_headerSortDown";
                }
            }
            this.FetchData();
            $("#" + s + '  span:first-child').attr("class", SortDir);
        },
       async AddPhase(){
           var vm=this;
            var url = 'controller=Project&action=AddUpdatePhase'
            await DataService.CheckPrivilege(url).then(async function (response) {
                if (response.data) {
                    vm.isShowPhaseModel=true;
                } else {
                    vm.ShowAlert(vm.$t('NotAuthorizedSection'), "failure", true, "Alert");
                }
            });

        },
        ClosePhaseModel(){
             this.ClearFeildValue();
            this.isShowPhaseModel=false;
        }, 
        CheckAssociatePhase(Id)
        {
            debugger
           var vm=this;
           var url=`ProjectId=${0}&Id=${Id}&type=PHASE`;
            DataService.CheckAssociatePhaseAndStage(url).then((response)=>{
              if(response !='')
               if(response.data.result =='EXIST')
               {
                vm.ShowAlert(vm.$t('AlreadyExistsInAnotherProject', [vm.$t('Phase')]), "warning", true, vm.$t("Alert"));
                return true;
               }
               else{
                return false;
               }
           });
        },
        Updatestatus(id,statusId)
        {       debugger
            var vm=this;
                   vm.confirmR(this.$t('ConfirmUpdateStatusRecord'),true, this.$t('UpdateCommonStatus'),function(result) { 
                                var VarObject = {
                                    ID: id,
                                    StatusId: statusId,
                                    IsFor: 'TALYGEN_PHASE'
                                }
                                debugger
                                if(vm.CheckAssociatePhase(id))
                                {return}
                                var objectPostString = JSON.stringify(VarObject);
                                DataService.CommonUpdateStatus(objectPostString).then(function (response) {
                                         if (response.data != null) {
                                            if (response.data.status === 'Success') {
                                                vm.ShowAlert(vm.$t("RecordUpdatedSuccessfully"), "success",vm.$t('Alert'));
                                                vm.PrevStatus = vm.StatusId;
                                                if (typeof vm.callbackfunction != 'undefined' && vm.callbackfunction != null) {
                                                    vm.callbackfunction();
                                                }
                                            } else {
                                                vm.ShowAlert(vm.$t("UnknownErrorOccur"), "failure", true, vm.$t('Alert'));
                                            }
                                        } else {
                                            vm.ShowAlert(vm.$t("UnknownErrorOccur"), "failure", true, vm.$t('Alert'));
                                        }
                                         
                                    }, function (response) {
                                         debugger
                                    });
                                
                            },function(result) {
                                vm.FetchData();
                            })

        },   
      async ActiveInActivePhase(id,type){   
            var vm = this;
            var url = 'controller=Project&action=DeletePhase'
            await DataService.CheckPrivilege(url).then(async function (response) {
                if (response.data) {
                    var val = "";
            vm.isLoading = true;
            if(id == 0){
                $('.chkItems:checkbox:checked').not("[id^='chkAll']").each(function () {                
                    if (val.length > 0)
                        val += ',';
                    val += $(this).val();
                });
            }else{
                val=id;
            }          
            if (val != null) {
                vm.confirmR(vm.$t("phaseApproveReject"), true, vm.$t("Phase"), function () {  
                     vm.CheckAssociatePhase(val);
                    var refId=0;
                    if(type == 'Active'){
                        refId=1001;
                    }else if(type == 'InActive'){
                        refId=1002;
                    }else if(type == 'Delete'){
                        refId=1003;
                    }               
                    var postJSON = {
                        ids: val,
                        moduleName: 'Phase',
                        subModuleCode: "Phase",
                        refCode: 'PROJCET_TALYGEN_PHASE',
                        refId: refId,
                    };
                    var objectPostString = JSON.stringify(postJSON);
                    DataService.CommonCommonDelete(objectPostString).then(function (response) {
                        vm.isLoading = false;
                        if (response.data[0].Status == "Success") {
                            if(type=='Delete'){
                                vm.ShowAlert(vm.$t('DeletedSuccess', [vm.$t('Status')]), "success", true, vm.$t("Alert"));
                            }
                            else{
                                vm.ShowAlert(vm.$t('UpdatedSuccess', [vm.$t('Status')]), "success", true, vm.$t("Alert"));
                            }
                            vm.FetchData();
                            vm.Key++;                                                     
                        }
                        else {
                            vm.ShowAlert(vm.$t('DeleteError'), "warning", true, vm.$t('Alert'));
                        }                   
                    });
                });
            }
            else {
                vm.ShowAlert(vm.$t("Selectanyrecordtodelete"));
            }
            vm.isLoading = false;    
                } else {
                    vm.ShowAlert(vm.$t('NotAuthorizedSection'), "failure", true, "Alert");
                }
            });
        },
        
        OnSubmit()
        {
            debugger
            var vm=this;
            vm.isLoading=true;
            var phaseName=vm.$refs.AddPhaseRecord.getPropertyValue("PhaseName", "value");
            var phaseStatus=vm.$refs.AddPhaseRecord.getPropertyValue("Status", "value");
            var phaseDescription=vm.$refs.AddPhaseRecord.getPropertyValue("Description", "value");
            var phaseid=vm.PHASE_ID > 0 ? vm.PHASE_ID : 0;
            var jsonobj={
              
                PHASEID :phaseid,
                PhaseName :phaseName,
                PhaseDescription :phaseDescription,
                StatusId :phaseStatus
            }
            var postString=JSON.stringify(jsonobj);
            DataService.AddSavePhase(postString).then((response)=>{
                debugger
                if(response.data != null)
                {
                   if(response.data.result.DATA[0].VALUE=="INSERT")
                   {
                    vm.ShowAlert(vm.$t('AddedSuccess',[vm.$t('Phase')]), "success", true,  vm.$t("Alert"));
                   }
                  else if(response.data.result.DATA[0].VALUE=="UPDATE")
                   {
                    vm.ShowAlert(vm.$t("RecordUpdatedSuccessfully"), "success", vm.$t('Alert'));
                   }
                   else if(response.data.result.DATA[0].VALUE=="RECORD EXISTS")
                   {
                    vm.ShowAlert(vm.$t('AlreadyExists', [vm.$t('Phase')]), "failure", true, vm.$t('Alert'));
                   }
                   else
                   {
                    vm.ShowAlert(vm.$t("UnknownErrorOccur"), "failure", true, vm.$t('Alert'));
                   }
                }
                vm.isLoading=false;
                vm.ClearFeildValue();
                vm.FetchData();
            });
        },
        ClearFeildValue()
        {
            var vm=this;
            vm.PHASE_ID=0;
             vm.FormSchema[0].Data[0].value='';
            vm.FormSchema[0].Data[1].value='';
            vm.FormSchema[1].Data[0].value='';
            this.isShowPhaseModel=false;
        }
    }
}
</script>